import { mapState } from "vuex";
export default {
  props: {
    skin: Object
  },
  methods: {
    getSkinUrl(championId, index) {
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/skins/${championId}/loading/${championId}_${index}.jpg`;
    }
  },
  computed: mapState({
    isSelected(state) {
      return state.csCurrentPlayer.selectedSkin && state.csCurrentPlayer.selectedSkin.name === this.skin.name || !state.csCurrentPlayer.selectedSkin && this.skin.name === "default";
    }
  })
};
